  ('elementary-acfc4025-moex-00661', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '行政機關基於法律授權，對多數不特定人民就一般事項所作抽象之對外發生法律效果之規定，係指下列 何種行政行為？', '["行政處分", "行政規則", "法規命令", "行政指導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00662', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '政府近年來陸續提高基本工資，是為了直接保障下列那一市場的那一方權益？', '["商品市場的需求方", "商品市場的供給方", "要素市場的需求方", "要素市場的供給方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00663', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '個人對其財產之所有權有自由使用、收益、處分並排除他人干涉之權利。上述內容主要係民法何種原則 的內涵？', '["物權法定原則", "契約自由原則", "所有權絕對原則", "所有權社會化原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00664', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '下列何者屬於行政法院所審理之案件？', '["馬路施工未設警示標誌，導致人民甲騎車路經該地失速滑倒受傷，因而提出國家賠償訴訟", "乙本為軍校公費生，於軍校畢業後拒絕服役，遭國防部追討就學四年期間之學雜費全額", "市政府公務人員丙，遭檢舉利用工程採購職權收受廠商回扣，被以貪污治罪條例起訴", "人民丁向縣政府承購之國宅，因施工瑕疵導致嚴重漏水，丁請求縣政府賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00665', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '下表是大雄上公民與社會課時，所寫下黑板上老師整理關於我國各項選舉所採用的選舉制度表格，但因 為漏列了實施該選制的實例，請幫大雄依甲乙丙的順序選出相對應的選舉： 實例 單一選區相對多數制 複數選區制 政黨比例代表制 甲 ν ν 乙 ν 丙 ν 總統 ν', '["縣市議員、區域立委、縣市長", "立法委員、縣市議員、縣市長", "山地原住民立委、縣市議員、立法委員", "區域立委、山地原住民立委、縣市議員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00666', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '甲某日於道路上駕車，驚見酒後駕車的乙逆向朝自己急速駛來，甲為閃避乙車，僅能選擇往路邊圍牆撞 去，最後導致丙宅圍牆傾倒毀損。試問，甲面對丙所提出的毀損罪告訴，得依下列何種規定阻卻違法？', '["緊急避難", "正當防衛", "依法令之行為", "得被害人同意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00667', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '隨著全球化的發展，國際交流愈來愈頻繁，關於國際交流之敘述，下列何者正確？', '["國民外交係指國民受政府囑託進行跨國交流", "各國政府之交流仍以中央政府外交機關為限", "國際組織下建立的國際協定要求所有成員國皆須加入", "聯合國無法直接管轄各成員國之國際關係與國內治理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00668', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '甲民族數千年居住於某地區，目前為乙民族國家的一個自治區，藉由其傳統統治機制行使自治，甲希望 依民族自決原則獨立為一國。甲欲成立國家尚缺下列那一項國家成立要件？', '["領土", "政府", "人民", "主權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00669', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '下列關於國家、統治者與人民關係的說法，何者最符合當今對民主政治的想像？', '["元首為國家主權之象徵，行使所有統治權力", "人民為國家構成要件之一，須服從國家之各種規範", "國家主權應為人民所掌有，一國元首須由人民選舉產生", "國家應是實現人民權益保障的機制，而非人民之支配者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00670', 'elementary-acfc4025', 'elementary-acfc4025-moex-111-b3f42868', 'sub-elementary-acfc4025-01', NULL, 'single_choice', '假設某一封閉的市場經濟體系只生產手機與腳踏車兩種商品且機會成本遞增。考慮兩種商品之生產可能 選擇，如果人們變得熱愛騎腳踏車，則與原生產點比較起來，新的生產點其：', '["生產手機與腳踏車的機會成本都會增加", "生產手機與腳踏車的機會成本都會減少", "生產手機的機會成本會增加，且生產腳踏車的機會成本會減少", "生產手機的機會成本會減少，且生產腳踏車的機會成本會增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:27+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
